 1→const FormatNotificationType = (type) => {
 2→    const notifType = type;
 3→
 4→    const notificationTypeArray = {
 5→        like: 'Liked your post',
 6→        comment: 'Commented on your post',
 7→        reply: 'Replied on your comment',
 8→        follow: 'Follows you',
 9→        repost: 'Reposted your post',
10→        opinion_reply: 'Replied to your opinion',
11→        constellation_request: 'Wants to link stars with you',
12→        constellation_accepted: 'Accepted your constellation link'
13→    }
14→
15→    return notificationTypeArray[type] || 'Unknown notification'
16→}
17→
